#!/bin/bash
echo "--- PIR 1: External source to OT ports (5900, 3389, 80, 443) ---"
awk '($6 == "5900" || $6 == "3389" || $6 == "80" || $6 == "443") && !($3 ~ /^10\./ || $3 ~ /^172\.(1[6-9]|2[0-9]|3[0-1])\./ || $3 ~ /^192\.168\./) {print $1, $3, $4, $5, $6, $7, $12}' conn.log

echo "--- PIR 2: Internal source to external non-standard high ports (sample) ---"
awk '($6 > 1023 && $6 != "3389" && $6 != "5900" && $6 != "8080" && $6 != "8000" && $6 != "8443") && ($3 ~ /^10\./ || $3 ~ /^172\.(1[6-9]|2[0-9]|3[0-1])\./ || $3 ~ /^192\.168\./) && !($5 ~ /^10\./ || $5 ~ /^172\.(1[6-9]|2[0-9]|3[0-1])\./ || $5 ~ /^192\.168\./) {print $1, $3, $4, $5, $6, $7, $12}' conn.log | head -n 20

echo "--- PIR 3: Internal scanning of ICS ports (502, 20000, 20001) ---"
awk '($6 == "502" || $6 == "20000" || $6 == "20001") && ($3 ~ /^10\./ || $3 ~ /^172\.(1[6-9]|2[0-9]|3[0-1])\./ || $3 ~ /^192\.168\./) && ($5 ~ /^10\./ || $5 ~ /^172\.(1[6-9]|2[0-9]|3[0-1])\./ || $5 ~ /^192\.168\./) {print $3, $5}' conn.log | sort | uniq -c | sort -rn | head -n 20
